const rawJson = $input.first().json;
const formTriggerData = $("Form Trigger").first().json;

// -----------------------------
// 1. Read Ollama JSON response
// -----------------------------
let responseText =
  rawJson.message?.content ||
  rawJson.response ||
  rawJson.text ||
  rawJson.output ||
  rawJson.content ||
  "";

if (typeof responseText === "object") {
  responseText = JSON.stringify(responseText);
}

if (!responseText) {
  throw new Error(
    "No cover letter response found from Ollama. Output keys: " +
      Object.keys(rawJson).join(", ")
  );
}

responseText = String(responseText)
  .replace(/```json/gi, "")
  .replace(/```latex/gi, "")
  .replace(/```tex/gi, "")
  .replace(/```/g, "")
  .trim();

const jsonStart = responseText.indexOf("{");
const jsonEnd = responseText.lastIndexOf("}");

if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error("Ollama did not return valid JSON. Response: " + responseText);
}

responseText = responseText.slice(jsonStart, jsonEnd + 1);

let parsed;

try {
  parsed = JSON.parse(responseText);
} catch (error) {
  throw new Error(
    "Could not parse Ollama JSON. Error: " +
      error.message +
      ". Response: " +
      responseText
  );
}

// -----------------------------
// 2. Helpers
// -----------------------------
function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 70);
}

function escapeRegex(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function escapeLatexText(value) {
  return String(value || "")
    .replace(/\\/g, "\\textbackslash{}")
    .replace(/&/g, "\\&")
    .replace(/%/g, "\\%")
    .replace(/#/g, "\\#")
    .replace(/_/g, "\\_")
    .replace(/\$/g, "\\$")
    .replace(/\{/g, "\\{")
    .replace(/\}/g, "\\}")
    .replace(/~/g, "\\textasciitilde{}")
    .replace(/\^/g, "\\textasciicircum{}");
}

function cleanPlainParagraph(value) {
  let text = String(value || "")
    .replace(/```json/gi, "")
    .replace(/```latex/gi, "")
    .replace(/```tex/gi, "")
    .replace(/```/g, "")
    .replace(/:contentReference\[[^\]]*\]\{[^}]*\}/g, "")
    .replace(/\\documentclass[\s\S]*?\\begin\{document\}/gi, "")
    .replace(/\\end\{document\}/gi, "")
    .replace(/^#+\s*/gm, "")
    .replace(/\*\*(.*?)\*\*/g, "$1")
    .trim();

  // Remove greetings/signatures if model adds them
  text = text
    .replace(/^\\textbf\{Hello,\}\s*/i, "")
    .replace(/^Hello,?\s*/i, "")
    .replace(/^Dear\s+Hiring\s+Manager,?\s*/i, "")
    .replace(/^Dear\s+Recruiter,?\s*/i, "")
    .replace(/^Dear\s+Team,?\s*/i, "")
    .replace(/Sincerely,[\s\S]*$/i, "")
    .replace(/Thank you for your time and consideration\.?[\s\S]*$/i, "")
    .replace(/Thank you for considering my application\.?[\s\S]*$/i, "")
    .trim();

  // Remove corporate filler
  text = text
    .replace(/I am excited to apply[^.]*\.\s*/gi, "")
    .replace(/I am highly motivated[^.]*\.\s*/gi, "")
    .replace(/I am eager to join your team[^.]*\.\s*/gi, "")
    .replace(/I am confident that I can make a significant contribution[^.]*\.\s*/gi, "")
    .replace(/align perfectly/gi, "align well")
    .replace(/—/g, "-")
    .replace(/–/g, "-")
    .trim();

  return text;
}

function splitIntoParagraphs(value) {
  const text = String(value || "").trim();

  if (!text) return [];

  return text
    .split(/\n\s*\n+/)
    .map((p) => p.trim())
    .filter(Boolean);
}

// -----------------------------
// 3. Get paragraphs
// -----------------------------
let paragraphs = [];

if (Array.isArray(parsed.body)) {
  paragraphs = parsed.body.map(cleanPlainParagraph).filter(Boolean);
} else if (typeof parsed.body === "string") {
  paragraphs = splitIntoParagraphs(parsed.body).map(cleanPlainParagraph).filter(Boolean);
} else if (typeof parsed.cover_letter === "string") {
  paragraphs = splitIntoParagraphs(parsed.cover_letter).map(cleanPlainParagraph).filter(Boolean);
}

if (!paragraphs.length) {
  throw new Error("No body paragraphs found in Ollama JSON. Parsed keys: " + Object.keys(parsed).join(", "));
}

// Force max 4 paragraphs
paragraphs = paragraphs.slice(0, 4);

// If model returns fewer than 4, keep what exists but do not fail
if (paragraphs.length < 3) {
  throw new Error("Cover letter body too short. Paragraph count: " + paragraphs.length);
}

// -----------------------------
// 4. Build bold keywords
// -----------------------------
const fallbackKeywords = [
  "full-stack",
  "backend",
  "frontend",
  "REST APIs",
  "APIs",
  "React",
  "Next.js",
  "Redux",
  "Node.js",
  "Express",
  "JavaScript",
  "TypeScript",
  "Python",
  "Django",
  "Java",
  "Spring Boot",
  "SQL",
  "PostgreSQL",
  "MongoDB",
  "AWS",
  "Azure",
  "GCP",
  "Docker",
  "Kubernetes",
  "CI/CD",
  "Git",
  "testing",
  "debugging",
  "dashboards",
  "cloud",
  "microservices",
  "data-driven",
  "Power BI",
  "PowerBI"
];

const ollamaKeywords = Array.isArray(parsed.bold_keywords)
  ? parsed.bold_keywords
  : [];

const boldKeywords = [...new Set([...ollamaKeywords, ...fallbackKeywords])]
  .filter(Boolean)
  .map((value) => String(value).trim())
  .filter(Boolean)
  .sort((a, b) => b.length - a.length);

function boldLatexText(latexText) {
  let result = String(latexText || "");

  // Protect existing textbf just in case
  const protectedParts = [];
  result = result.replace(/\\textbf\{[^{}]*\}/g, (match) => {
    const token = `@@BOLD_PROTECT_${protectedParts.length}@@`;
    protectedParts.push(match);
    return token;
  });

  for (const keyword of boldKeywords) {
    const cleanKeyword = String(keyword || "").trim();
    if (!cleanKeyword) continue;

    const regex = new RegExp(
      `(^|[^A-Za-z0-9\\\\])(${escapeRegex(cleanKeyword)})(?=[^A-Za-z0-9]|$)`,
      "gi"
    );

    result = result.replace(regex, (full, before, match) => {
      if (match.includes("@@BOLD_PROTECT_")) return full;
      return `${before}\\textbf{${match}}`;
    });
  }

  protectedParts.forEach((part, index) => {
    result = result.replace(`@@BOLD_PROTECT_${index}@@`, part);
  });

  // Fix nested bolds
  result = result
    .replace(/\\textbf\{\\textbf\{([^{}]*)\}\}/g, "\\textbf{$1}")
    .replace(/\\textbf\{REST \\textbf\{APIs\}\}/g, "\\textbf{REST APIs}")
    .replace(/\\textbf\{RESTful \\textbf\{APIs\}\}/g, "\\textbf{RESTful APIs}")
    .replace(/\\textbf\{full-\\textbf\{stack\}\}/g, "\\textbf{full-stack}");

  return result;
}

const latexParagraphs = paragraphs.map((paragraph) => {
  const escaped = escapeLatexText(paragraph);
  return boldLatexText(escaped);
});

const generatedBody = latexParagraphs.join("\n\n\\vspace{0.7em}\n\n");

// -----------------------------
// 5. File naming
// -----------------------------
const companyRaw = formTriggerData.company_name || rawJson.company_name || "company";
const roleRaw = formTriggerData.role_title || rawJson.role_title || "role";

const company = slugify(companyRaw) || "company";
const role = slugify(roleRaw) || "role";

const baseName = `cover_letter_${company}_${role}`;
const workDir = `/home/node/.n8n-files/${baseName}`;

// -----------------------------
// 6. Cover letter LaTeX template for pdflatex
// -----------------------------
const latexTemplate = String.raw`\documentclass[11pt]{article}

\usepackage[a4paper, margin=0.85in]{geometry}
\usepackage[T1]{fontenc}
\usepackage[utf8]{inputenc}
\usepackage{lmodern}
\usepackage[hidelinks]{hyperref}
\usepackage{xcolor}
\usepackage{parskip}
\usepackage{microtype}

\pagenumbering{gobble}
\setlength{\parindent}{0pt}
\setlength{\parskip}{0.55em}

\begin{document}

\textbf{Jaydipsinh Padhiyar}\\
2309 Brunswicks St\\
Halifax, NS B3K 2Z1\\
\href{mailto:jaydipadhiyar27@gmail.com}{jaydipadhiyar27@gmail.com}\\
+1 (782) 882 6260\\
\href{https://jaydipsinh.netlify.app/}{Portfolio}

\vspace{1em}

\textbf{Hello,}

\vspace{0.6em}

OLD BODY PLACEHOLDER

\vspace{0.8em}

Sincerely,\\
\textbf{Jaydipsinh Padhiyar}

\end{document}
`;

const updatedLatex = latexTemplate.replace("OLD BODY PLACEHOLDER", generatedBody);

const latexBase64 = Buffer.from(updatedLatex, "utf8").toString("base64");

const changeLogText = JSON.stringify(
  {
    note: "Generated cover letter body and compiled with pdflatex.",
    company_name: companyRaw,
    role_title: roleRaw,
    summary: parsed.summary || "",
    paragraph_count: paragraphs.length,
    bold_keywords_used: boldKeywords,
    paragraphs
  },
  null,
  2
);

const changeLogBase64 = Buffer.from(changeLogText, "utf8").toString("base64");

return [
  {
    json: {
      company_name: companyRaw,
      role_title: roleRaw,

      generated_body: generatedBody,
      updated_latex: updatedLatex,
      latex_base64: latexBase64,

      change_log_base64: changeLogBase64,

      base_name: baseName,
      work_dir: workDir,
      tex_path: `${workDir}/${baseName}.tex`,
      pdf_path: `${workDir}/${baseName}.pdf`,
      log_path: `${workDir}/${baseName}_changes.json`,

      tex_file_name: `${baseName}.tex`,
      pdf_file_name: `${baseName}.pdf`,
      log_file_name: `${baseName}_changes.json`
    }
  }
];

const input = $input.first().json;

const companyName = input.company_name || input["Company Name"] || "";
const roleTitle = input.role_title || input["Role Title"] || "";
const jobDescription = input.job_description || input["Job Description"] || "";
const customPrompt = input.custom_prompt || input["Custom Prompt"] || "";
const resumeLatex =
  input.resume_latex ||
  input["Resume Latex"] ||
  input["Resume LaTeX"] ||
  "";

const extraNotes = input.extra_notes || input["Extra Notes"] || "";
const latexTemplate =
  input.latex_template ||
  input["LaTeX Template"] ||
  input["Latex Template"] ||
  "";

if (!jobDescription) {
  throw new Error(
    "Job Description is required. Available input keys: " +
      Object.keys(input).join(", ")
  );
}

if (!resumeLatex) {
  throw new Error(
    "Resume Latex is required. Available input keys: " +
      Object.keys(input).join(", ")
  );
}

function cleanLatexToResumeSummary(latex) {
  let text = String(latex || "");

  text = text
    // Remove LaTeX comments
    .split("\n")
    .filter((line) => !line.trim().startsWith("%"))
    .join("\n")

    // Keep useful visible text from common LaTeX commands
    .replace(/\\href\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textbf\{([^{}]*)\}/g, "$1")
    .replace(/\\textit\{([^{}]*)\}/g, "$1")
    .replace(/\\textcolor\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\section\{([^{}]*)\}/g, "\nSECTION: $1\n")
    .replace(/\\headingBf\{([^{}]*)\}\{([^{}]*)\}/g, "\n$1 | $2\n")
    .replace(/\\headingIt\{([^{}]*)\}\{([^{}]*)\}/g, "$1 | $2\n")

    // Convert bullets
    .replace(/\\item\[[^\]]*\]/g, "-")
    .replace(/\\item/g, "-")

    // Remove environments
    .replace(/\\begin\{[^{}]*\}/g, "")
    .replace(/\\end\{[^{}]*\}/g, "")

    // Remove remaining LaTeX commands but keep regular text
    .replace(/\\[a-zA-Z]+\*?(?:\[[^\]]*\])?/g, "")

    // Cleanup
    .replace(/[{}]/g, "")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  // Keep it small so the model does not copy full resume structure
  return text.slice(0, 4500);
}

const resumeSummary = cleanLatexToResumeSummary(resumeLatex);

const safeJobDescription = String(jobDescription).slice(0, 5000);
const safeCustomPrompt = String(customPrompt).slice(0, 1200);
const safeExtraNotes = String(extraNotes).slice(0, 1200);

const prompt = `
You are writing a short cover letter body.

CRITICAL OUTPUT RULE:
Return ONLY one valid JSON object.
Do not write markdown.
Do not write code fences.
Do not write explanations.
Do not write anything before the JSON.
Do not write anything after the JSON.

The JSON object must have EXACTLY these 3 keys:
{
  "body": [
    "Paragraph 1",
    "Paragraph 2",
    "Paragraph 3",
    "Paragraph 4"
  ],
  "bold_keywords": [],
  "summary": ""
}

Do not add any other keys.
Do not add skills.
Do not add experience.
Do not add education.
Do not add projects.
Do not add certifications.
Do not add resume sections.

BODY RULES:
- body must contain exactly 4 paragraphs.
- Total body length must be 250 to 350 words.
- Each paragraph should be 3 to 5 sentences.
- Do not include Hello.
- Do not include Dear Hiring Manager.
- Do not include Sincerely.
- Do not include a name, email, phone, address, links, or signature.
- Do not use bullet points.
- Do not use em dash.
- Do not say "I am excited to apply".
- Do not sound corporate, fake, desperate, or overly formal.
- Use a confident but grounded early-career voice.
- Use simple natural language.
- Use only facts from the resume, job description, and extra notes.
- Do not invent experience, tools, dates, companies, numbers, awards, or achievements.

PARAGRAPH CONTENT:
Paragraph 1: Why this company or role is interesting, connected to the job description.
Paragraph 2: Relevant experience from the resume connected to the role.
Paragraph 3: Ownership, debugging, collaboration, systems thinking, and learning.
Paragraph 4: Natural confident closing.

BOLD KEYWORDS RULES:
- bold_keywords must contain 8 to 15 short exact keywords from the resume or job description.
- Examples: React, Next.js, Python, Django, REST APIs, SQL, AWS, Azure, Docker, Kubernetes, CI/CD, dashboards, debugging, backend, full-stack.

Company:
${companyName}

Role:
${roleTitle}

Job description:
${safeJobDescription}

Resume:
${resumeSummary}

User style:
${safeCustomPrompt}

Extra notes:
${safeExtraNotes}
`;

return [
  {
    json: {
      company_name: companyName,
      role_title: roleTitle,
      job_description: jobDescription,
      custom_prompt: customPrompt,
      resume_latex: resumeLatex,
      resume_summary: resumeSummary,
      extra_notes: extraNotes,
      latex_template: latexTemplate,

      // IMPORTANT:
      // Your HTTP Request node must send this exact object as the body:
      // {{ $json.ollama_body }}
      ollama_body: {
        model: "gemma3:latest",
        messages: [
          {
            role: "user",
            content: prompt
          }
        ],
        stream: false,
        format: "json",
        options: {
          temperature: 0.15,
          num_predict: 650,
          top_p: 0.75,
          repeat_penalty: 1.2,
          num_ctx: 8192
        }
      }
    }
  }
];

