:root {
	--font-family: 'Open Sans', sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;
	--font-size-body: 12px;
	--font-size-label: 13px;
	--font-size-test-notice: 11px;
	--font-size-input: 13px;
	--font-size-header: 20px;
	--font-size-paragraph: 13px;
	--font-size-link: 12px;
	--font-size-error: 12px;
	--font-size-subheader: 13px;

	--color-background: #fbfcfe;
	--color-test-notice-text: #e6a23d;
	--color-test-notice-bg: #fefaf6;
	--color-test-notice-border: #f6dcb7;
	--color-card-bg: #ffffff;
	--color-card-border: #dbdfe7;
	--color-card-shadow: rgba(99, 77, 255, 0.06);
	--color-header: #3f3f46;
	--color-label: #444444;
	--color-input-border: #dbdfe7;
	--color-input-text: #36383d;
	--color-focus-border: rgb(90, 76, 194);
	--color-submit-btn-bg: #ff6d5a;
	--color-submit-btn-text: #ffffff;
	--color-required: #ff6d5a;

	--border-radius-card: 10px;
	--border-radius-input: 6px;
	--card-border-radius: 10px;

	--padding-container-top: 8px;
	--padding-card: 16px;
	--padding-test-notice-vertical: 8px;
	--padding-test-notice-horizontal: 16px;
	--margin-bottom-card: 8px;
	--padding-form-input: 8px;
	--card-padding: 16px;
	--card-margin-bottom: 8px;

	/* Make form wide */
	--container-width: min(96vw, 1500px);

	--submit-btn-height: 42px;
	--box-shadow-card: 0px 4px 16px 0px var(--color-card-shadow);
}

/* Full page */
html,
body {
	width: 100% !important;
	min-height: 100vh !important;
	margin: 0 !important;
	padding: 0 !important;
	overflow-x: hidden !important;
	background: var(--color-background) !important;
}

/* Make all containers wide */
body > div,
main,
.container,
[class*="container"] {
	max-width: 1500px !important;
	width: 96vw !important;
}

/* Main card */
#n8n-form,
[class*="card"] {
	max-width: 1500px !important;
	width: 96vw !important;
	margin: 8px auto !important;
	padding: 16px 20px !important;
	box-sizing: border-box !important;
}

/* Smaller title area */
h1 {
	font-size: 20px !important;
	margin: 0 0 4px 0 !important;
}

p {
	font-size: 13px !important;
	line-height: 1.3 !important;
	margin: 0 0 8px 0 !important;
}

/* Labels */
label {
	font-size: 13px !important;
	margin-bottom: 3px !important;
	font-weight: 600 !important;
}

/* Inputs */
input,
textarea,
select {
	width: 100% !important;
	box-sizing: border-box !important;
	font-size: 13px !important;
	padding: 8px 10px !important;
	border-radius: 6px !important;
}

/* Make fields compact */
textarea {
	min-height: 90px !important;
	max-height: 180px !important;
	resize: vertical !important;
	font-family: Consolas, "Courier New", monospace !important;
	font-size: 12px !important;
	line-height: 1.25 !important;
}

/* Bigger boxes, but still one-page friendly */
textarea[name="job_description"],
textarea[name="resume_latex"] {
	min-height: 190px !important;
	max-height: 230px !important;
}

textarea[name="custom_prompt"],
textarea[name="extra_notes"] {
	min-height: 105px !important;
	max-height: 140px !important;
}

/* Reduce field spacing */
form div,
[class*="form"] div {
	margin-bottom: 6px !important;
}

/* Submit button compact */
button,
button[type="submit"] {
	height: 42px !important;
	min-height: 42px !important;
	padding: 8px 16px !important;
	font-size: 14px !important;
	font-weight: 700 !important;
	width: 100% !important;
	margin-top: 6px !important;
}

/* Test notice compact */
[class*="test"],
[class*="notice"] {
	max-width: 1500px !important;
	width: 96vw !important;
	margin: 8px auto !important;
	padding: 8px 14px !important;
	font-size: 11px !important;
	box-sizing: border-box !important;
}

/* Hide extra whitespace if n8n adds wrappers */
br {
	display: none !important;
}

/* Mobile fallback */
@media (max-width: 900px) {
	:root {
		--container-width: 96vw;
	}

	#n8n-form,
	[class*="card"] {
		width: 96vw !important;
		padding: 14px !important;
	}

	textarea[name="job_description"],
	textarea[name="resume_latex"] {
		min-height: 160px !important;
	}
}

