parameters.jsCode:
const input = $input.first().json;

const resumeLatex = input.resume_latex || "";
const jobDescription = input.job_description || "";
const companyName = input.company_name || "";
const roleTitle = input.role_title || "";
const extraNotes = input.extra_notes || "";

if (!resumeLatex) {
  throw new Error("No resume_latex found from Resume form.");
}

if (!jobDescription) {
  throw new Error("No job_description found from Resume form.");
}

// -----------------------------
// Helpers
// -----------------------------
function normalize(value) {
  return String(value || "")
    .replace(/\\href\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textcolor\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textbf\{([^{}]*)\}/g, "$1")
    .replace(/\\textit\{([^{}]*)\}/g, "$1")
    .replace(/\\texttt\{([^{}]*)\}/g, "$1")
    .replace(/\\small\{([^{}]*)\}/g, "$1")
    .replace(/[{}\\]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function escapeRegex(value) {
  return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function extractBlockBetweenSections(latex, startSection, endRegex) {
  const startRegex = new RegExp(`\\\\section\\{${escapeRegex(startSection)}\\}`, "i");
  const startMatch = latex.match(startRegex);
  if (!startMatch) return "";
  const afterStart = latex.slice(startMatch.index + startMatch[0].length);
  const endMatch = afterStart.match(endRegex);
  const endIndex = endMatch ? endMatch.index : afterStart.length;
  return afterStart.slice(0, endIndex);
}

function extractSectionEntries(block, type) {
  const entries = [];
  const headingRegex = /\\headingBf\{([^{}]+)\}(?:\{([^{}]*)\})?/g;
  const matches = [...block.matchAll(headingRegex)];

  for (let i = 0; i < matches.length; i++) {
    const current = matches[i];
    const next = matches[i + 1];
    const heading = normalize(current[1]);
    const startIndex = current.index;
    const endIndex = next ? next.index : block.length;
    const sectionLatex = block.slice(startIndex, endIndex);

    const bullets = [];
    const bulletRegex = /\\item\s+([\s\S]*?)(?=\n\s*\\item|\n\s*\\end\{resume_list\}|\n\s*\\headingBf|\n\s*\\section|$)/g;

    let bulletMatch;
    while ((bulletMatch = bulletRegex.exec(sectionLatex)) !== null) {
      const rawBullet = String(bulletMatch[1] || "");
      if (rawBullet.trim().startsWith("%")) continue;
      const bullet = normalize(rawBullet);
      if (bullet) bullets.push(bullet);
    }

    if (heading && bullets.length) {
      entries.push({
        section: heading,
        type,
        bullets: bullets.slice(0, 5)
      });
    }
  }

  return entries;
}

function keywordSet(value) {
  const stopWords = new Set([
    "the", "and", "for", "with", "you", "your", "our", "are", "this", "that",
    "from", "will", "work", "role", "team", "have", "has", "using", "used",
    "into", "about", "their", "they", "them", "what", "where", "when"
  ]);
  return new Set(
    normalize(value)
      .toLowerCase()
      .split(/[^a-z0-9+#.]+/)
      .map((word) => word.trim())
      .filter((word) => word.length >= 3 && !stopWords.has(word))
  );
}

function scoreSection(section, jdSet) {
  const sectionText = `${section.section} ${section.type} ${section.bullets.join(" ")}`;
  const sectionSet = keywordSet(sectionText);
  let score = 0;
  for (const word of sectionSet) {
    if (jdSet.has(word)) score += 1;
  }
  const text = sectionText.toLowerCase();
  const boostWords = [
    "react", "typescript", "javascript", "node", "express", "rest", "api", "apis",
    "postgresql", "sql", "azure", "gcp", "aws", "docker", "kubernetes", "terraform",
    "cloud", "microservices", "data", "pipeline", "testing", "deployment", "ci/cd",
    "full-stack", "backend"
  ];
  for (const word of boostWords) {
    if (text.includes(word)) score += 2;
  }
  return score;
}

// -----------------------------
// Extract Experience and Projects
// -----------------------------
const experienceBlock = extractBlockBetweenSections(
  resumeLatex,
  "Experience",
  /\\section\{Education\}|\\section\{Projects\}|\\section\{Skills\}|\\section\{Certifications\}|\\end\{document\}/i
);

const projectsBlock = extractBlockBetweenSections(
  resumeLatex,
  "Projects",
  /\\section\{Certifications\s*\\&\s*Contributions\}|\\section\{Certifications\}|\\section\{Education\}|\\section\{Skills\}|\\end\{document\}/i
);

const experienceSections = extractSectionEntries(experienceBlock, "experience");
const projectSections = extractSectionEntries(projectsBlock, "project");

let targetSections = [...experienceSections, ...projectSections];

if (!targetSections.length) {
  throw new Error("Could not extract Experience or Project sections from resume LaTeX.");
}

// -----------------------------
// Select only top relevant sections
// -----------------------------
const jdSet = keywordSet(jobDescription);

targetSections = targetSections
  .map((section) => ({
    ...section,
    relevance_score: scoreSection(section, jdSet)
  }))
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, 4);

const targetSectionText = targetSections
  .map((item, index) => {
    const bulletText = item.bullets
      .map((bullet, bulletIndex) => `${bulletIndex + 1}. ${bullet}`)
      .join("\n");
    return `${index + 1}. ${item.section} (${item.type})\n${bulletText}`;
  })
  .join("\n\n");

// FIX 1: Increased JD limit from 2800 → 1800 to keep total prompt 
// well under context window and leave room for output tokens
const safeJobDescription = String(jobDescription).slice(0, 1800);
const safeExtraNotes = String(extraNotes).slice(0, 500);

const prompt = `You are tailoring a resume to a job description.

Return ONLY one valid JSON object. No markdown. No explanations. No LaTeX. No code fences. Nothing before or after the JSON.

The JSON must have EXACTLY these keys:
{ "summary": "", "bold_keywords": [], "sections": [] }

COMPANY: ${companyName}
ROLE: ${roleTitle}

JOB DESCRIPTION:
${safeJobDescription}

EXTRA NOTES:
${safeExtraNotes}

TARGET SECTIONS:
${targetSectionText}

TASK: For each target section add exactly 1 new bullet and comment out exactly 1 existing bullet.
- old_text must exactly match an existing bullet from that section.
- Do not invent experience, tools, metrics, or achievements.
- New bullets must be under 26 words, no LaTeX, no \\item.

JSON shape:
{
  "summary": "Short summary of tailoring.",
  "bold_keywords": ["keyword1","keyword2"],
  "sections": [
    {
      "section": "Exact section heading",
      "type": "experience",
      "add_points": ["New bullet"],
      "comment_out": [{ "old_text": "Exact existing bullet", "reason": "Why removed" }]
    }
  ]
}

RULES:
- JSON only. All 4 sections required. Exactly 1 add_points and 1 comment_out per section.
- bold_keywords: 8–15 short keywords from JD or resume.
- Prefer Azure, TypeScript, PostgreSQL, Docker, microservices, REST API, CI/CD keywords.`;

return [
  {
    json: {
      resume_latex: resumeLatex,
      job_description: jobDescription,
      company_name: companyName,
      role_title: roleTitle,
      extra_notes: extraNotes,
      target_sections: targetSections,
      ollama_body: {
        model: "gemma3:latest",
        messages: [
          {
            role: "user",
            content: prompt
          }
        ],
        stream: false,
        // FIX 2: Increased from 1100 → 2000 so JSON output isn't cut off mid-way
        // 4 sections × ~120 tokens each + summary + keywords ≈ 700–900 tokens minimum
        options: {
          temperature: 0.12,
          num_predict: 2000,
          top_p: 0.7,
          repeat_penalty: 1.22,
          num_ctx: 8192
        }
      }
    }
  }
];

const rawJson = $input.first().json;
const formData = $("Resume").first().json;

const originalResume = formData.resume_latex || rawJson.resume_latex || "";

if (!originalResume) {
  throw new Error("No resume_latex found from Resume form.");
}

// ─────────────────────────────────────────
// 1. Parse Ollama response
// ─────────────────────────────────────────
let responseText =
  rawJson.message?.content ||
  rawJson.response ||
  rawJson.text ||
  rawJson.output ||
  rawJson.content ||
  "";

if (typeof responseText === "object") {
  responseText = JSON.stringify(responseText);
}

if (!responseText) {
  throw new Error("No Ollama response found. Keys: " + Object.keys(rawJson).join(", "));
}

responseText = String(responseText)
  .replace(/```json/gi, "")
  .replace(/```latex/gi, "")
  .replace(/```tex/gi, "")
  .replace(/```/g, "")
  .trim();

const jsonStart = responseText.indexOf("{");
const jsonEnd = responseText.lastIndexOf("}");

if (jsonStart === -1 || jsonEnd === -1 || jsonEnd <= jsonStart) {
  throw new Error("Ollama did not return valid JSON. Got: " + responseText.slice(0, 300));
}

let edits;
try {
  edits = JSON.parse(responseText.slice(jsonStart, jsonEnd + 1));
} catch (err) {
  throw new Error("JSON parse failed: " + err.message + "\nRaw: " + responseText.slice(0, 400));
}

if (edits.suggestions && !edits.sections) edits = edits.suggestions;

if (!Array.isArray(edits.sections)) {
  throw new Error("Ollama JSON missing sections array.");
}

// Normalize sections
edits.sections = edits.sections
  .filter((s) => s && s.section)
  .slice(0, 4)
  .map((s) => ({
    section: String(s.section || "").trim(),
    type: s.type === "project" ? "project" : "experience",
    add_points: Array.isArray(s.add_points)
      ? s.add_points.slice(0, 1).map((p) => String(p || "").trim()).filter(Boolean)
      : [],
    comment_out: Array.isArray(s.comment_out)
      ? s.comment_out.slice(0, 1).map((item) => ({
          old_text: String(item?.old_text || "").trim(),
          reason: String(item?.reason || "Less relevant to this role").trim()
        }))
      : []
  }))
  .filter((s) => s.add_points.length > 0 && s.comment_out.length > 0);

if (!edits.sections.length) {
  throw new Error("No usable sections after normalization. Raw edits: " + JSON.stringify(edits));
}

// ─────────────────────────────────────────
// 2. Helpers
// ─────────────────────────────────────────
function slugify(value) {
  return String(value || "")
    .trim().toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 70);
}

function escapeRegex(str) {
  return String(str || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function ensurePeriod(text) {
  const t = String(text || "").trim();
  return t && !/[.!?]$/.test(t) ? t + "." : t;
}

function escapeLatexText(text) {
  return String(text || "")
    .replace(/\\/g, "\\textbackslash{}")
    .replace(/&/g, "\\&")
    .replace(/%/g, "\\%")
    .replace(/#/g, "\\#")
    .replace(/_/g, "\\_")
    .replace(/\$/g, "\\$")
    .replace(/\{/g, "\\{")
    .replace(/\}/g, "\\}")
    .replace(/~/g, "\\textasciitilde{}")
    .replace(/\^/g, "\\textasciicircum{}");
}

// Strip ALL LaTeX and punctuation down to plain comparable words
function stripLatex(text) {
  return String(text || "")
    .replace(/\\href\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textcolor\{[^{}]*\}\{([^{}]*)\}/g, "$1")
    .replace(/\\textbf\{([^{}]*)\}/g, "$1")
    .replace(/\\textit\{([^{}]*)\}/g, "$1")
    .replace(/\\texttt\{([^{}]*)\}/g, "$1")
    .replace(/\\small\{([^{}]*)\}/g, "$1")
    .replace(/\\item\s*/gi, "")
    .replace(/[{}\\]/g, "")
    .replace(/[""]/g, '"')
    .replace(/['']/g, "'")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();
}

function wordOverlapScore(a, b) {
  const wordsOf = (str) =>
    new Set(str.split(/\s+/).filter((w) => w.length >= 4));
  const setA = wordsOf(stripLatex(a));
  const setB = wordsOf(stripLatex(b));
  if (!setA.size || !setB.size) return 0;
  let common = 0;
  for (const w of setA) if (setB.has(w)) common++;
  return common / Math.min(setA.size, setB.size);
}

// ─────────────────────────────────────────
// 3. Section + bullet finding (FIXED)
// ─────────────────────────────────────────

// FIX: Match headingBf lines by checking if the FIRST arg contains the target name
// Your LaTeX: \headingBf{K8s Microservice}{(GCP, Terraform...)}
// Previous code tried to match full normalized line — this was the root bug
function findSectionLineIndex(lines, sectionName) {
  const target = stripLatex(sectionName);
  if (!target) return -1;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (!line.includes("\\headingBf")) continue;

    // Extract just the first argument of \headingBf{...}{...}
    const firstArgMatch = line.match(/\\headingBf\{([^{}]+)\}/);
    if (!firstArgMatch) continue;

    const firstArg = stripLatex(firstArgMatch[1]);

    // Match if target is contained in firstArg or exact
    if (firstArg.includes(target) || target.includes(firstArg)) {
      return i;
    }
  }

  return -1;
}

function findSectionEndIndex(lines, startIdx) {
  for (let i = startIdx + 1; i < lines.length; i++) {
    const t = lines[i].trim();
    if (
      t.startsWith("\\headingBf") ||
      t.startsWith("\\section") ||
      t.startsWith("\\end{document}")
    ) {
      return i;
    }
  }
  return lines.length;
}

// Get all active (non-commented) \item lines in a range
function getActiveBullets(lines, startIdx, endIdx) {
  const bullets = [];
  for (let i = startIdx; i < endIdx; i++) {
    const t = lines[i].trim();
    if (!t.startsWith("%") && /^\\item\s+/.test(t)) {
      bullets.push({ lineIdx: i, text: lines[i] });
    }
  }
  return bullets;
}

// Find the \end{resume_list} line within a section to insert before it
function findInsertLine(lines, startIdx, endIdx) {
  for (let i = endIdx - 1; i > startIdx; i--) {
    if (lines[i].trim().startsWith("\\end{resume_list}")) return i;
  }
  // Fallback: insert before section end
  return endIdx;
}

// ─────────────────────────────────────────
// 4. Apply edits
// ─────────────────────────────────────────
let updatedResume = originalResume;
const changeLog = [];

// PASS 1: Comment out old bullets
for (const sectionEdit of edits.sections) {
  const { section, comment_out } = sectionEdit;
  const targetText = comment_out[0].old_text;
  const reason = comment_out[0].reason;

  const lines = updatedResume.split("\n");
  const startIdx = findSectionLineIndex(lines, section);

  if (startIdx === -1) {
    changeLog.push({ action: "comment_out", changed: false, section, reason: `Section "${section}" not found in LaTeX` });
    continue;
  }

  const endIdx = findSectionEndIndex(lines, startIdx);
  const bullets = getActiveBullets(lines, startIdx, endIdx);

  if (!bullets.length) {
    changeLog.push({ action: "comment_out", changed: false, section, reason: "No active bullets found in section" });
    continue;
  }

  // Try exact substring match first, then fall back to best overlap score
  let best = null;
  let bestScore = 0;

  for (const bullet of bullets) {
    const stripped = stripLatex(bullet.text);
    const strippedTarget = stripLatex(targetText);

    // Exact or near-exact substring match
    if (stripped.includes(strippedTarget) || strippedTarget.includes(stripped)) {
      best = bullet;
      bestScore = 1;
      break;
    }

    // Word overlap fallback — lowered threshold to 0.3
    const score = wordOverlapScore(bullet.text, targetText);
    if (score > bestScore) {
      best = bullet;
      bestScore = score;
    }
  }

  // FIX: Lowered threshold from 0.45 → 0.3 to catch partial matches
  if (!best || bestScore < 0.3) {
    // Last resort: pick the SHORTEST bullet (usually the weakest/most generic)
    best = bullets.reduce((a, b) =>
      stripLatex(a.text).length <= stripLatex(b.text).length ? a : b
    );
    changeLog.push({
      action: "comment_out",
      changed: true,
      section,
      matched_line: best.text.trim(),
      reason: reason + " (fallback: shortest bullet)",
      score: bestScore
    });
  } else {
    changeLog.push({
      action: "comment_out",
      changed: true,
      section,
      matched_line: best.text.trim(),
      reason,
      score: bestScore
    });
  }

  // Replace the matched line with commented-out version
  const newLines = updatedResume.split("\n");
  newLines[best.lineIdx] =
    `% REMOVED (${escapeLatexText(reason)})\n% ${best.text.trim()}`;
  updatedResume = newLines.join("\n");
}

// PASS 2: Insert new bullets
for (const sectionEdit of edits.sections) {
  const { section, add_points } = sectionEdit;
  const newText = add_points[0];

  const lines = updatedResume.split("\n");
  const startIdx = findSectionLineIndex(lines, section);

  if (startIdx === -1) {
    changeLog.push({ action: "add_point", changed: false, section, reason: `Section "${section}" not found` });
    continue;
  }

  const endIdx = findSectionEndIndex(lines, startIdx);
  const insertAt = findInsertLine(lines, startIdx, endIdx);

  const newBullet = "\\item " + ensurePeriod(escapeLatexText(newText));
  lines.splice(insertAt, 0, newBullet);
  updatedResume = lines.join("\n");

  changeLog.push({ action: "add_point", changed: true, section, new_text: newText });
}

// ─────────────────────────────────────────
// 5. Bold keywords on newly added bullets only
// ─────────────────────────────────────────
const fallbackKeywords = [
  "TypeScript", "JavaScript", "RESTful APIs", "REST APIs", "Node.js", "Express.js",
  "Spring Boot", "React", "Redux", "Next.js", "Vue.js", "Java", "Python", "Django",
  "PostgreSQL", "MongoDB", "DynamoDB", "SQL", "AWS", "Azure", "GCP", "Docker",
  "Kubernetes", "Terraform", "CI/CD", "Jenkins", "GitLab", "microservices",
  "cloud-native", "full-stack", "backend", "frontend", "DevOps", "testing",
  "deployment", "data pipeline", "dashboards", "PowerBI"
];

const boldKeywords = [
  ...new Set([
    ...(Array.isArray(edits.bold_keywords) ? edits.bold_keywords : []),
    ...fallbackKeywords
  ])
]
  .map((k) => String(k || "").trim())
  .filter(Boolean)
  .sort((a, b) => b.length - a.length); // longest first to avoid partial replacement

const addedTexts = new Set(
  changeLog
    .filter((e) => e.action === "add_point" && e.changed)
    .map((e) => stripLatex(e.new_text))
);

function applyBolding(line) {
  if (!line.trim().startsWith("\\item")) return line;

  // Only bold newly added lines
  if (!addedTexts.has(stripLatex(line.replace(/^\\item\s*/i, "").replace(/\.$/, "")))) {
    return line;
  }

  let result = line;
  for (const kw of boldKeywords) {
    if (!kw) continue;
    const regex = new RegExp(
      `(?<![A-Za-z0-9\\\\])(${escapeRegex(kw)})(?![A-Za-z0-9])`,
      "gi"
    );
    result = result.replace(regex, (match) => {
      // Don't double-bold
      return result.includes(`\\textbf{${match}}`) ? match : `\\textbf{${match}}`;
    });
  }

  // Clean up any accidental double-bolding
  result = result
    .replace(/\\textbf\{\\textbf\{([^{}]*)\}\}/g, "\\textbf{$1}")
    .replace(/\\textbf\{([\w.-]+)\s+\\textbf\{([\w.-]+)\}\}/g, "\\textbf{$1 $2}");

  return result;
}

updatedResume = updatedResume.split("\n").map(applyBolding).join("\n");

// ─────────────────────────────────────────
// 6. LaTeX safety cleanup
// ─────────────────────────────────────────
updatedResume = updatedResume
  .replace(/\\textbf\{\\textbf\{([^{}]*)\}\}/g, "\\textbf{$1}")
  .replace(/\\textbf\{RESTful \\textbf\{APIs\}\}/g, "\\textbf{RESTful APIs}")
  .replace(/\\textbf\{REST \\textbf\{APIs\}\}/g, "\\textbf{REST APIs}")
  .replace(/\\textbf\{cloud-\\textbf\{native\}\}/g, "\\textbf{cloud-native}")
  .replace(/\\textbf\{full-\\textbf\{stack\}\}/g, "\\textbf{full-stack}")
  .replace(/(-?\d+)px/g, "$1pt");

// ─────────────────────────────────────────
// 7. Output
// ─────────────────────────────────────────
const companyRaw = formData.company_name || rawJson.company_name || "company";
const roleRaw = formData.role_title || rawJson.role_title || "role";
const baseName = `resume_${slugify(companyRaw) || "company"}_${slugify(roleRaw) || "role"}`;
const workDir = `/home/node/.n8n-files/${baseName}`;

const successfulEdits = changeLog.filter((e) => e.changed);
const failedEdits = changeLog.filter((e) => !e.changed);

return [
  {
    json: {
      updated_resume_latex: updatedResume,
      resume_base64: Buffer.from(updatedResume, "utf8").toString("base64"),

      change_log: changeLog,
      change_log_base64: Buffer.from(
        JSON.stringify({
          summary: edits.summary || "",
          sections_processed: edits.sections.length,
          successful_edits: successfulEdits.length,
          failed_edits: failedEdits.length,
          edits,
          changeLog,
          bold_keywords_used: boldKeywords
        }, null, 2),
        "utf8"
      ).toString("base64"),

      // Useful for debugging
      sections_found: edits.sections.map((s) => s.section),
      successful_edits: successfulEdits.length,
      failed_edits: failedEdits.length,
      failed_details: failedEdits,

      relevant_summary: edits.summary || "",
      bold_keywords: boldKeywords,

      work_dir: workDir,
      tex_path: `${workDir}/${baseName}.tex`,
      pdf_path: `${workDir}/${baseName}.pdf`,
      log_path: `${workDir}/${baseName}_changes.json`,
      tex_file_name: `${baseName}.tex`,
      pdf_file_name: `${baseName}.pdf`,
      log_file_name: `${baseName}_changes.json`
    }
  }
];

const stdout = $input.first().json.stdout || "";
const stderr = $input.first().json.stderr || "";

const texPath = stdout.trim();

if (!texPath || texPath.includes("ERROR")) {
  throw new Error("No TEX file found. stdout: " + stdout + " stderr: " + stderr);
}

const fileName = texPath.split("/").pop();

return [
  {
    json: {
      tex_path: texPath,
      tex_file_name: fileName
    }
  }
];

const input = $input.first().json;

const fileTypeRaw = input.file_type || "";
const companyRaw = input.company_name || "";
const roleRaw = input.role_title || "";

if (!fileTypeRaw) {
  throw new Error("File Type is required.");
}

if (!companyRaw) {
  throw new Error("Company Name is required.");
}

if (!roleRaw) {
  throw new Error("Role Title is required.");
}

function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 70);
}

const fileType = slugify(fileTypeRaw);
const company = slugify(companyRaw);
const role = slugify(roleRaw);

let prefix = "";

if (fileType === "resume") {
  prefix = "resume";
} else if (fileType === "cover_letter") {
  prefix = "cover_letter";
} else {
  throw new Error("Invalid file type. Use resume or cover_letter.");
}

const baseName = `${prefix}_${company}_${role}`;
const texFileName = `${baseName}.tex`;

return [
  {
    json: {
      file_type: fileType,
      company_name: companyRaw,
      role_title: roleRaw,
      base_name: baseName,
      tex_file_name: texFileName
    }
  }
];
